import{c as a,Z as r,Q as o,j as i,m as n,o as s}from"./chunks/framework.BA1dEi98.js";const m=JSON.parse('{"title":"About LibrisLog","description":"","frontmatter":{},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1780262269000}'),d={name:"about.md"};function l(c,t,h,g,u,p){const e=r("CommitInfo");return o(),i("div",null,[t[0]||(t[0]=n('<h1 id="about-librislog" tabindex="-1">About LibrisLog <a class="header-anchor" href="#about-librislog" aria-label="Permalink to &quot;About LibrisLog&quot;">​</a></h1><p>LibrisLog is a <strong>multi-user book tracking web application</strong> designed for readers who want to organize their library, track reading progress, and gain insights into their reading habits.</p><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to &quot;Features&quot;">​</a></h2><ul><li><strong>Library Management</strong>: Organize books into four reading statuses — Want to Read, Currently Reading, Read, and Did Not Finish</li><li><strong>Book Import</strong>: Search Open Library, Google Books, and Hardcover.app. Scan ISBN barcodes for quick lookup</li><li><strong>Reading Progress</strong>: Track pages read over time with a visual timeline and calendar heatmap</li><li><strong>Statistics Dashboard</strong>: Charts showing pages read per month, books finished, language distribution, and more</li><li><strong>Cover Management</strong>: Automatic cover image scraping from multiple sources with manual override</li><li><strong>Data Portability</strong>: Export/import library as JSON or CSV. Full backup and restore functionality</li><li><strong>REST API</strong>: Full API with OpenAPI documentation for programmatic access</li><li><strong>Multilingual</strong>: English and German UI support</li><li><strong>Themes</strong>: Light, dark, and custom DaisyUI themes with persistent preferences</li></ul><h2 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Component</th><th>Technology</th></tr></thead><tbody><tr><td>Frontend</td><td>Svelte 5 + SvelteKit + Tailwind CSS 4 + DaisyUI 5</td></tr><tr><td>Backend</td><td>FastAPI + SQLModel + Alembic + Pydantic v2</td></tr><tr><td>Database</td><td>SQLite</td></tr><tr><td>Search Sources</td><td>Open Library, Google Books, Hardcover.app, AbeBooks, Amazon</td></tr><tr><td>Charts</td><td>Chart.js + chartjs-chart-matrix + chartjs-plugin-zoom</td></tr><tr><td>Icons</td><td>Lucide Svelte</td></tr><tr><td>Scraping</td><td>curl-cffi + Scrapling + BrowserForge</td></tr><tr><td>Auth</td><td>Session cookies, optional OIDC (Authlib)</td></tr><tr><td>Barcode</td><td>html5-qrcode</td></tr><tr><td>Dates</td><td>dayjs</td></tr><tr><td>Misc</td><td>cachetools, cryptography, restrictedpython, pycountry, passlib, hammerjs</td></tr><tr><td>Docs</td><td>VitePress + viewerjs</td></tr><tr><td>CI/Tests</td><td>pytest (backend), Vitest (frontend), Playwright (E2E)</td></tr></tbody></table><h2 id="author" tabindex="-1">Author <a class="header-anchor" href="#author" aria-label="Permalink to &quot;Author&quot;">​</a></h2><p>Created and maintained by <a href="https://github.com/codebude" target="_blank" rel="noreferrer">Raffael Herrmann</a>.</p><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h2><p>Released under the MIT License.</p>',10)),s(e)])}const f=a(d,[["render",l]]);export{m as __pageData,f as default};
